// Integration test for 图片压缩器 (image compressor / resizer / converter).
// Feeds a real 160×100 PNG fixture through the browser's Canvas pipeline and
// asserts concrete computed outputs: resized dimensions (percent + max-side),
// format conversion (JPEG/WebP), real byte-savings, batch summary, downloads,
// and removal. Captures thumb.png used as the homepage card thumbnail.
import { Buffer } from 'node:buffer';

// A deterministic 160×100 RGB gradient PNG (generated offline via Node zlib, no deps).
const FIXTURE_PNG_B64 = "";
const ORIG_W = 160, ORIG_H = 100;
const fixture = () => ({ name: 'fixture.png', mimeType: 'image/png', buffer: Buffer.from(FIXTURE_PNG_B64, 'base64') });

export default async function ({ page, toolURL, screenshot, assert }) {
  await page.goto(toolURL, { waitUntil: 'domcontentloaded' });
  await page.waitForSelector('#dropzone');

  const setQuality = async (q) => {
    await page.$eval('#qualityRange', (el, v) => { el.value = String(v); el.dispatchEvent(new Event('input', { bubbles: true })); }, q);
  };
  const process = async () => { await page.click('#processBtn'); };
  const waitOutDims = async (w, h) => {
    await page.waitForFunction(
      ([w, h]) => { const el = document.querySelector('.card .out-dims'); return !!el && el.textContent.includes(w) && el.textContent.includes(h); },
      [String(w), String(h)], { timeout: 6000 }
    );
  };
  const firstText = async (sel) => (await page.locator(sel).first().textContent()) || '';

  // ---- shell: back link + empty state ----
  assert((await page.locator('a.back').count()) === 1, 'has "← 返回工具集" link');
  assert(/返回工具集/.test(await firstText('a.back')), 'back link text correct');
  assert(await page.locator('#processBtn').isDisabled(), 'process button disabled when there are no images');
  assert(await page.locator('#downloadAllBtn').isDisabled(), 'download-all disabled when empty');

  // ---- add the fixture image ----
  await page.setInputFiles('#fileInput', fixture());
  await page.waitForSelector('.card');
  assert((await page.locator('.card').count()) === 1, 'one card appears after adding an image');
  const origDims = await firstText('.card .orig-dims');
  assert(/\b160\b/.test(origDims) && /\b100\b/.test(origDims), `original dims read as 160 × 100 (got "${origDims.trim()}")`);
  assert(!(await page.locator('#processBtn').isDisabled()), 'process button enabled once an image is present');

  // ---- resize by percent (50%) + convert to JPEG ----
  await page.selectOption('#resizeMode', 'percent');
  await page.fill('#resizeValue', '50');
  await page.selectOption('#formatSelect', 'image/jpeg');
  await setQuality(80);
  await process();
  await waitOutDims(80, 50); // 160×100 @ 50% must be exactly 80×50

  const outDims = await firstText('.card .out-dims');
  assert(/\b80\b/.test(outDims) && /\b50\b/.test(outDims), `50% resize → 80 × 50 (got "${outDims.trim()}")`);
  const fmt = await firstText('.card .out-fmt');
  assert(/JPEG/i.test(fmt), `format badge shows JPEG (got "${fmt.trim()}")`);
  const savings = await firstText('.card .savings');
  const svMatch = savings.match(/(\d+)%/);
  assert(/↓/.test(savings) && !!svMatch && Number(svMatch[1]) > 0, `real byte-savings shown as a positive reduction (got "${savings.trim()}")`);

  // ---- batch summary reflects the single processed image ----
  assert(await page.locator('#summary').isVisible(), 'summary panel becomes visible after processing');
  assert((await firstText('#sumCount')) === '1', 'summary count is 1');
  assert(/\d+%/.test(await firstText('#sumSaved')), 'summary shows an overall savings percentage');
  assert((await page.locator('#sumSaved').getAttribute('class') || '').includes('good'), 'overall savings styled as a reduction (good)');

  // ---- a per-image download fires with the right extension ----
  assert(!(await page.locator('#downloadAllBtn').isDisabled()), 'download-all enabled after a successful compress');
  const [dlJpg] = await Promise.all([
    page.waitForEvent('download'),
    page.locator('.card .dl-btn').first().click(),
  ]);
  assert(/\.jpg$/.test(dlJpg.suggestedFilename()), `per-image download is a .jpg (got "${dlJpg.suggestedFilename()}")`);

  // ---- convert to WebP: badge + download extension both follow ----
  await page.selectOption('#formatSelect', 'image/webp');
  await process();
  await page.waitForFunction(() => /WEBP/i.test(document.querySelector('.card .out-fmt')?.textContent || ''), null, { timeout: 6000 });
  assert(/WEBP/i.test(await firstText('.card .out-fmt')), 'format badge switches to WEBP');
  const [dlWebp] = await Promise.all([
    page.waitForEvent('download'),
    page.locator('.card .dl-btn').first().click(),
  ]);
  assert(/\.webp$/.test(dlWebp.suggestedFilename()), `download extension follows format → .webp (got "${dlWebp.suggestedFilename()}")`);

  // ---- resize by "max longest side" = 64 → 64 × 40 (160→64 ⇒ 100→40) ----
  await page.selectOption('#resizeMode', 'maxside');
  await page.fill('#resizeValue', '64');
  await process();
  await waitOutDims(64, 40);
  const outDims2 = await firstText('.card .out-dims');
  assert(/\b64\b/.test(outDims2) && /\b40\b/.test(outDims2), `max-side 64 → 64 × 40 (got "${outDims2.trim()}")`);

  // ---- "don't upscale" guard: percent 200% with the box checked keeps original size ----
  await page.selectOption('#resizeMode', 'percent');
  await page.fill('#resizeValue', '200');
  assert(await page.locator('#noUpscale').isChecked(), 'no-upscale is on by default');
  await process();
  await waitOutDims(ORIG_W, ORIG_H);
  const noUp = await firstText('.card .out-dims');
  assert(/\b160\b/.test(noUp) && /\b100\b/.test(noUp), `200% with no-upscale stays 160 × 100 (got "${noUp.trim()}")`);

  // ---- batch: add a second image, compress both ----
  await page.setInputFiles('#fileInput', fixture());
  await page.waitForFunction(() => document.querySelectorAll('.card').length === 2, null, { timeout: 4000 });
  assert((await page.locator('.card').count()) === 2, 'second image adds a second card (batch)');
  await page.selectOption('#resizeMode', 'percent');
  await page.fill('#resizeValue', '70');
  await page.selectOption('#formatSelect', 'image/webp');
  await setQuality(72);
  await process();
  await page.waitForFunction(() => document.querySelectorAll('.card .savings').length === 2, null, { timeout: 6000 });
  assert((await firstText('#sumCount')) === '2', 'summary count reflects 2 processed images');
  assert((await page.locator('.card .savings').count()) === 2, 'both cards report savings');

  // ---- settle a clean state and grab the thumbnail ----
  await page.waitForTimeout(120);
  await screenshot('thumb.png');

  // ---- removal: clearing cards resets the UI ----
  await page.locator('.card .rm-btn').first().click();
  await page.waitForFunction(() => document.querySelectorAll('.card').length === 1, null, { timeout: 4000 });
  assert((await page.locator('.card').count()) === 1, 'removing a card drops the count to 1');
  await page.locator('.card .rm-btn').first().click();
  await page.waitForFunction(() => document.querySelectorAll('.card').length === 0, null, { timeout: 4000 });
  assert(await page.locator('#processBtn').isDisabled(), 'process disabled again after all images removed');
  assert(!(await page.locator('#summary').isVisible()), 'summary hidden again when empty');
}
